class Student:
    """A class demonstrating basic encapsulation in Python"""

    def __init__(self, name, roll_no, marks):
        self.__name = name      # Private attribute (name mangled)
        self.__roll_no = roll_no
        self.__marks = marks

    # Property decorators for controlled access
    @property
    def name(self):
        return self.__name

    @property
    def roll_no(self):
        return self.__roll_no

    @property
    def marks(self):
        return self.__marks

    @marks.setter
    def marks(self, value):
        if 0 <= value <= 100:
            self.__marks = value
        else:
            raise ValueError("Marks must be between 0 and 100")

    def display_info(self):
        """Public method - abstraction of internal representation"""
        return f"Student: {self.__name}, Roll No: {self.__roll_no}, Marks: {self.__marks}"


# Usage
student = Student("Amit Kumar", "CS/2024/001", 85)
print(student.display_info())
print(f"Name: {student.name}")
print(f"Marks: {student.marks}")

# Modify marks through setter with validation
student.marks = 92
print(f"Updated Marks: {student.marks}")

# This will raise an error - demonstrates encapsulation
# student.marks = 150  # Uncomment to see ValueError

from abc import ABC, abstractmethod
from datetime import datetime
import random

class BankAccount(ABC):
    """Abstract base class demonstrating abstraction and encapsulation"""

    def __init__(self, account_holder, initial_balance=0):
        self.__account_holder = account_holder  # Private: encapsulating holder info
        self.__balance = initial_balance        # Private: encapsulating balance
        self.__account_number = self.__generate_account_number()
        self.__transactions = []                # Private: encapsulating transaction history

    def __generate_account_number(self):
        """Private method - abstraction of account generation logic"""
        return f"ACC{random.randint(100000, 999999)}"

    @property
    def account_number(self):
        return self.__account_number

    @property
    def balance(self):
        """Read-only property - abstraction of balance retrieval"""
        return self.__balance

    def deposit(self, amount):
        """Public interface for deposit - abstracts validation logic"""
        if amount > 0:
            self.__balance += amount
            self.__record_transaction("Deposit", amount)
            return f"Deposited: ₹{amount}. New Balance: ₹{self.__balance}"
        return "Invalid deposit amount"

    @abstractmethod
    def withdraw(self, amount):
        """Abstract method - each account type has different withdrawal rules"""
        pass

    def __record_transaction(self, txn_type, amount):
        """Private method - encapsulates transaction recording"""
        self.__transactions.append({
            "type": txn_type,
            "amount": amount,
            "timestamp": datetime.now()
        })

    def get_transaction_history(self):
        """Public interface to access private transaction data"""
        return self.__transactions


class SavingsAccount(BankAccount):
    """Concrete implementation with specific withdrawal rules"""

    def __init__(self, account_holder, initial_balance=0):
        super().__init__(account_holder, initial_balance)
        self.__min_balance = 500  # Private: minimum balance requirement

    def withdraw(self, amount):
        """Overrides abstract method with savings-specific logic"""
        if amount > 0 and (self.balance - amount) >= self.__min_balance:
            # Accessing private member of parent class (not recommended but possible)
            self._BankAccount__balance -= amount
            self._BankAccount__record_transaction("Withdrawal", amount)
            return f"Withdrawn: ₹{amount}. New Balance: ₹{self.balance}"
        return "Insufficient balance or below minimum balance"


# Usage
savings = SavingsAccount("Priya Sharma", 5000)
print(f"Account Number: {savings.account_number}")
print(savings.deposit(2000))
print(savings.withdraw(1500))
print(f"Final Balance: ₹{savings.balance}")
print(f"Transaction Count: {len(savings.get_transaction_history())}")

from abc import ABC, abstractmethod
from typing import List

class Product(ABC):
    """Abstract Product class - First level of abstraction"""

    def __init__(self, product_id, name, price):
        self.__product_id = product_id    # Encapsulated
        self.__name = name                  # Encapsulated
        self.__price = price                # Encapsulated

    @property
    def product_id(self):
        return self.__product_id

    @property
    def name(self):
        return self.__name

    @property
    def price(self):
        return self.__price

    @abstractmethod
    def get_category(self):
        pass

    def __str__(self):
        return f"{self.__name} (ID: {self.__product_id}) - ₹{self.__price}"


class Electronics(Product):
    """Concrete product category"""

    def __init__(self, product_id, name, price, warranty_months):
        super().__init__(product_id, name, price)
        self.__warranty = warranty_months   # Additional encapsulation

    def get_category(self):
        return "Electronics"

    @property
    def warranty(self):
        return self.__warranty


class ShoppingCart:
    """Encapsulated cart managing items - Second level of abstraction"""

    def __init__(self):
        self.__items = []   # Private list - encapsulates cart contents

    def add_item(self, product, quantity=1):
        """Public interface to add items - abstracts validation"""
        for item in self.__items:
            if item["product"].product_id == product.product_id:
                item["quantity"] += quantity
                return f"Updated {product.name} quantity to {item['quantity']}"

        self.__items.append({"product": product, "quantity": quantity})
        return f"Added {product.name} to cart"

    def remove_item(self, product_id):
        """Public interface to remove items"""
        for i, item in enumerate(self.__items):
            if item["product"].product_id == product_id:
                removed = self.__items.pop(i)
                return f"Removed {removed['product'].name}"
        return "Item not found"

    def get_total(self):
        """Calculates total - abstracts calculation logic"""
        return sum(item["product"].price * item["quantity"] for item in self.__items)

    def get_items(self):
        """Returns copy to prevent external modification (encapsulation)"""
        return self.__items.copy()


class OrderProcessor:
    """Third level - abstracts order processing complexity"""

    def __init__(self):
        self.__orders = []  # Encapsulated order storage

    def process_order(self, cart, customer_id):
        """Public interface - abstracts entire order processing"""
        if not cart.get_items():
            return "Cart is empty"

        # Create order (abstraction of all processing steps)
        order = {
            "order_id": f"ORD{len(self.__orders) + 1001}",
            "customer_id": customer_id,
            "items": cart.get_items(),
            "total": cart.get_total(),
            "status": "Confirmed"
        }

        self.__orders.append(order)
        return f"Order {order['order_id']} confirmed! Total: ₹{order['total']}"

    def get_orders(self):
        """Controlled access to order history"""
        return self.__orders


# Usage - Demonstrating multiple abstraction layers
cart = ShoppingCart()

# Create products (abstraction of product creation)
laptop = Electronics("ELEC001", "Gaming Laptop", 75000, 24)
keyboard = Electronics("ELEC002", "Mechanical Keyboard", 8500, 12)

# Add to cart (abstracts inventory management)
print(cart.add_item(laptop, 1))
print(cart.add_item(keyboard, 2))

# Process order (top-level abstraction)
processor = OrderProcessor()
print(processor.process_order(cart, "CUST/2024/001"))

# Show encapsulation - cannot access private members directly
